Steps:
[GQL-OP get_config]
  query {
    productConfiguration(
      configurableProductId: "@td(CFG_LAPTOP.id)"
      storeId: "{{STORE_ID}}"
      cultureName: "en-US"
      currencyCode: "USD"
    ) {
      configurationSections { id name isRequired type maxLength dependsOnSectionId options { id text product { id name } listPrice { amount currency { code } } } }
    }
  }
[GQL-EXEC get_config]
[GQL-CAPTURE get_config.data.productConfiguration.configurationSections.0.id → SECTION_RAM_ID]
[GQL-CAPTURE get_config.data.productConfiguration.configurationSections.0.options.0.product.id → OPT_RAM_BASE_ID]

[GQL-OP get_plain]
  query {
    productConfiguration(
      configurableProductId: "@td(CFG_HOODIE.id)"
      storeId: "{{STORE_ID}}"
      cultureName: "en-US"
      currencyCode: "USD"
    ) {
      configurationSections { id type }
    }
  }
[GQL-EXEC get_plain]

[GQL-OP bogus_config]
  query {
    productConfiguration(
      configurableProductId: "00000000-0000-0000-0000-000000000000"
      storeId: "{{STORE_ID}}"
    ) {
      configurationSections { id }
    }
  }
[GQL-EXEC bogus_config]

[GQL-OP get_text]
  query {
    productConfiguration(
      configurableProductId: "@td(CFG_RING.id)"
      storeId: "{{STORE_ID}}"
      cultureName: "en-US"
    ) {
      configurationSections { id name type isRequired maxLength allowCustomText allowTextOptions }
    }
  }
[GQL-EXEC get_text]

[GQL-OP get_cascade]
  query {
    productConfiguration(
      configurableProductId: "@td(CFG_CONDITIONAL_BIKE.id)"
      storeId: "{{STORE_ID}}"
    ) {
      configurationSections { id name isRequired dependsOnSectionId }
    }
  }
[GQL-EXEC get_cascade]

[GQL-OP get_def]
  query {
    productConfiguration(
      configurableProductId: "@td(CFG_LAPTOP.id)"
      storeId: "{{STORE_ID}}"
    ) {
      configurationSections { id type isRequired options { product { id } } }
    }
  }
[GQL-EXEC get_def]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.id → SECTION_RAM_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.options.0.product.id → OPT_RAM_BASE_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.1.id → SECTION_STORAGE_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.1.options.0.product.id → OPT_STORAGE_BASE_ID]
[GQL-OP create_preview]
[GQL-VARS create_preview] {"configurationSections": [{"sectionId": "{{SECTION_RAM_ID}}", "type": "Product", "option": {"productId": "{{OPT_RAM_BASE_ID}}", "quantity": 1, "selectedForCheckout": true}}, {"sectionId": "{{SECTION_STORAGE_ID}}", "type": "Product", "option": {"productId": "{{OPT_STORAGE_BASE_ID}}", "quantity": 1, "selectedForCheckout": true}}]}
  mutation CreateConfiguredLineItem($configurationSections: [ConfigurationSectionInput]) {
    createConfiguredLineItem(command: {
      storeId: "{{STORE_ID}}"
      currencyCode: "USD"
      cultureName: "en-US"
      configurableProductId: "@td(CFG_LAPTOP.id)"
      configurationSections: $configurationSections
    }) {
      id quantity
      listPrice { amount currency { code } }
      extendedPrice { amount currency { code } }
    }
  }
[GQL-EXEC create_preview]

[GQL-OP create_empty]
[GQL-VARS create_empty] {"configurationSections": []}
  mutation CreateConfiguredLineItem($configurationSections: [ConfigurationSectionInput]) {
    createConfiguredLineItem(command: {
      storeId: "{{STORE_ID}}"
      currencyCode: "USD"
      configurableProductId: "@td(CFG_LAPTOP.id)"
      configurationSections: $configurationSections
    }) {
      id quantity
    }
  }
[GQL-EXEC create_empty]

[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP cleanup_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_pre]
[GQL-OP get_def]
  query { productConfiguration(configurableProductId: "@td(CFG_LAPTOP.id)" storeId: "{{STORE_ID}}") { configurationSections { id type options { product { id } } } } }
[GQL-EXEC get_def]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.id → SECTION_RAM_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.options.0.product.id → OPT_RAM_BASE_ID]
[GQL-OP add_item]
  mutation AddItem($qty: Int!) { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(CFG_LAPTOP.id)" quantity: $qty }) { id items { id productId } } }
[GQL-VARS add_item] {"qty": 1}
[GQL-EXEC add_item]
[GQL-CAPTURE add_item.data.addItem.items.0.id → LINE_ITEM_ID]
[GQL-OP add_section]
[GQL-VARS add_section] {"configurationSection": {"sectionId": "{{SECTION_RAM_ID}}", "type": "Product", "option": {"productId": "{{OPT_RAM_BASE_ID}}", "quantity": 1, "selectedForCheckout": true}}}
  mutation AddConfigurationItem($configurationSection: ConfigurationSectionInput!) {
    addConfigurationItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" lineItemId: "{{LINE_ITEM_ID}}" configurationSection: $configurationSection }) {
      id items { id configurationItems { id sectionId type productId } }
    }
  }
[GQL-EXEC add_section]
[GQL-OP read_back]
  query { configurationItems(storeId: "{{STORE_ID}}" currencyCode: "USD" lineItemId: "{{LINE_ITEM_ID}}" userId: "{{USER_ID}}") { configurationItems { id sectionId type productId } } }
[GQL-EXEC read_back]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_post]

